.hero-butterfly {
  position: absolute;
  top: 7rem;
  left: clamp(1.5rem, 10vw, 9rem);
  z-index: 15;
  width: clamp(42px, 5vw, 64px);
  opacity: 0.9;
  pointer-events: none;
  filter: drop-shadow(0 4px 16px rgba(31, 20, 2, 0.3));
  animation: butterfly-float 7s ease-in-out infinite;
}

.hero-butterfly svg {
  display: block;
  width: 100%;
  height: auto;
}

@keyframes butterfly-float {
  0%,
  100% {
    transform: translate3d(0, 0, 0) rotate(-4deg);
  }

  50% {
    transform: translate3d(12px, -14px, 0) rotate(5deg);
  }
}

